/*
 * mm.c - Segregated free list allocator with:
 *   - 12 size classes with explicit doubly-linked free lists (LIFO)
 *   - Best-fit within size class, first-fit for larger classes
 *   - Footer elimination for allocated blocks (prev_alloc bit in header)
 *   - 8-byte aligned block sizes for reduced overhead
 *   - In-place realloc with next-block merging and heap extension
 *   - Immediate boundary-tag coalescing
 */

#include <stdbool.h>
#include <stdint.h>
#include <stdio.h>
#include <string.h>

#include "memlib.h"
#include "mm.h"

team_t team = {
	/* Team name */
	"BSCS Bench",
	/* First member's full name */
	"BSCS Bench Agent",
	/* First member's NetID */
	"bscs1",
	/* Second member's full name (leave blank if none) */
	"",
	/* Second member's NetID (leave blank if none) */
	""
};

/* Basic constants */
#define WSIZE      sizeof(void *)  /* Word size: 8 bytes on 64-bit */
#define DSIZE      (2 * WSIZE)     /* Double word: 16 bytes */
#define CHUNKSIZE  (1 << 12)       /* Default heap extension: 4096 bytes */
#define MIN_BLK    (4 * WSIZE)     /* Min block: hdr + next + prev + ftr = 32 */
#define NUM_CLASSES 12             /* Number of segregated free list classes */

#define MAX(x, y) ((x) > (y) ? (x) : (y))

/* Pack size and flag bits into a header/footer word */
#define PACK(size, flags) ((size) | (flags))

/* Read and write a word at address p */
#define GET(p)      (*(uintptr_t *)(p))
#define PUT(p, val) (*(uintptr_t *)(p) = (val))

/* Flag bits stored in low 3 bits of header */
#define ALLOC_BIT      0x1
#define PREV_ALLOC_BIT 0x2

/* Extract size and flags from a header/footer word */
#define GET_SIZE(p)       (GET(p) & ~(uintptr_t)0x7)
#define GET_ALLOC(p)      (GET(p) & ALLOC_BIT)
#define GET_PREV_ALLOC(p) (GET(p) & PREV_ALLOC_BIT)

/* Given block ptr bp, compute address of its header and footer */
#define HDRP(bp) ((char *)(bp) - WSIZE)
#define FTRP(bp) ((char *)(bp) + GET_SIZE(HDRP(bp)) - DSIZE)

/* Given block ptr bp, compute address of next and previous blocks */
#define NEXT_BLKP(bp) ((char *)(bp) + GET_SIZE(((char *)(bp) - WSIZE)))
#define PREV_BLKP(bp) ((char *)(bp) - GET_SIZE(((char *)(bp) - DSIZE)))

/* Free list pointers stored in the payload area of free blocks */
#define NEXT_FREEP(bp) (*(void **)(bp))
#define PREV_FREEP(bp) (*(void **)((char *)(bp) + WSIZE))

/* Global variables (scalar pointers only — no arrays or structs) */
static char *heap_listp;   /* Points to prologue block payload */
static char *fl_heads;     /* Points to free list head array in the heap */

/* Access free list head for class i */
#define FL_HEAD(i) (*(void **)(fl_heads + (i) * WSIZE))

/* Internal helper prototypes */
static void *coalesce(void *bp);
static void *extend_heap(size_t size);
static void *find_fit(size_t asize);
static void place(void *bp, size_t asize);
static void insert_block(void *bp);
static void remove_block(void *bp);
static int class_index(size_t size);

/* Heap checker prototypes */
static void checkblock(void *bp);
static void printblock(void *bp);
void checkheap(bool verbose);

/*
 * class_index - Return the segregated list index for a given block size.
 *   Fine-grained classes for small sizes, power-of-2 for larger.
 */
static int
class_index(size_t size)
{
	if (size <= 32) return 0;
	if (size <= 40) return 1;
	if (size <= 48) return 2;
	if (size <= 64) return 3;
	if (size <= 128) return 4;
	if (size <= 256) return 5;
	if (size <= 512) return 6;
	if (size <= 1024) return 7;
	if (size <= 2048) return 8;
	if (size <= 4096) return 9;
	if (size <= 8192) return 10;
	return 11;
}

/*
 * insert_block - Insert a free block at the head of its size class list (LIFO).
 */
static void
insert_block(void *bp)
{
	int idx = class_index(GET_SIZE(HDRP(bp)));
	void *head = FL_HEAD(idx);

	NEXT_FREEP(bp) = head;
	PREV_FREEP(bp) = NULL;
	if (head != NULL)
		PREV_FREEP(head) = bp;
	FL_HEAD(idx) = bp;
}

/*
 * remove_block - Remove a free block from its segregated list.
 */
static void
remove_block(void *bp)
{
	int idx = class_index(GET_SIZE(HDRP(bp)));
	void *prev = PREV_FREEP(bp);
	void *next = NEXT_FREEP(bp);

	if (prev != NULL)
		NEXT_FREEP(prev) = next;
	else
		FL_HEAD(idx) = next;
	if (next != NULL)
		PREV_FREEP(next) = prev;
}

/*
 * mm_init - Initialize the memory manager. Sets up the segregated free list
 *   heads, prologue, and epilogue blocks, then extends the heap.
 */
int
mm_init(void)
{
	int i;
	/* padding + NUM_CLASSES heads + prologue hdr + prologue ftr + epilogue hdr */
	size_t init_size = (1 + NUM_CLASSES + 3) * WSIZE;
	char *start;

	if ((start = mem_sbrk(init_size)) == (void *)-1)
		return (-1);

	PUT(start, 0);  /* Alignment padding */
	fl_heads = start + WSIZE;

	/* Initialize all free list heads to NULL */
	for (i = 0; i < NUM_CLASSES; i++)
		FL_HEAD(i) = NULL;

	/* Set up prologue and epilogue */
	char *pro = fl_heads + NUM_CLASSES * WSIZE;
	PUT(pro, PACK(DSIZE, ALLOC_BIT | PREV_ALLOC_BIT));          /* Prologue header */
	PUT(pro + WSIZE, PACK(DSIZE, ALLOC_BIT));                    /* Prologue footer */
	PUT(pro + DSIZE, PACK(0, ALLOC_BIT | PREV_ALLOC_BIT));      /* Epilogue header */
	heap_listp = pro + WSIZE;

	/* Extend the empty heap with a free block */
	if (extend_heap(CHUNKSIZE) == NULL)
		return (-1);
	return (0);
}

/*
 * mm_malloc - Allocate a block with at least "size" bytes of payload.
 *   Uses 8-byte alignment. Minimum block size is 32 bytes.
 */
void *
mm_malloc(size_t size)
{
	size_t asize;
	size_t extendsize;
	void *bp;

	if (size == 0)
		return (NULL);

	/* Block size = header (WSIZE) + payload, aligned to WSIZE, min MIN_BLK */
	asize = MAX(MIN_BLK, (size + WSIZE + (WSIZE - 1)) & ~(WSIZE - 1));

	if ((bp = find_fit(asize)) != NULL) {
		place(bp, asize);
		return (bp);
	}

	/* No fit found — extend the heap */
	extendsize = MAX(asize, CHUNKSIZE);
	if ((bp = extend_heap(extendsize)) == NULL)
		return (NULL);
	place(bp, asize);
	return (bp);
}

/*
 * mm_free - Free a block. Marks it as free (with footer) and coalesces.
 */
void
mm_free(void *bp)
{
	size_t size;

	if (bp == NULL)
		return;

	size = GET_SIZE(HDRP(bp));
	/* Mark as free, preserving prev_alloc bit */
	PUT(HDRP(bp), PACK(size, GET_PREV_ALLOC(HDRP(bp))));
	PUT(FTRP(bp), PACK(size, 0));
	coalesce(bp);
}

/*
 * mm_realloc - Reallocate a block. Optimizes in-place expansion
 *   by merging with next free block or extending the heap.
 */
void *
mm_realloc(void *ptr, size_t size)
{
	size_t oldsize, asize, next_size, avail, prev_a, extend, cpy;
	void *next_bp, *end_bp, *newptr, *rem, *after;

	if (size == 0) {
		mm_free(ptr);
		return (NULL);
	}
	if (ptr == NULL)
		return (mm_malloc(size));

	oldsize = GET_SIZE(HDRP(ptr));
	asize = MAX(MIN_BLK, (size + WSIZE + (WSIZE - 1)) & ~(WSIZE - 1));

	/* Current block is big enough — possibly shrink */
	if (asize <= oldsize) {
		if (oldsize - asize >= MIN_BLK) {
			prev_a = GET_PREV_ALLOC(HDRP(ptr));
			PUT(HDRP(ptr), PACK(asize, ALLOC_BIT | prev_a));
			rem = NEXT_BLKP(ptr);
			PUT(HDRP(rem), PACK(oldsize - asize, PREV_ALLOC_BIT));
			PUT(FTRP(rem), PACK(oldsize - asize, 0));
			coalesce(rem);
		}
		return (ptr);
	}

	/* Try to expand into next block */
	next_bp = NEXT_BLKP(ptr);
	next_size = GET_SIZE(HDRP(next_bp));
	avail = oldsize;

	if (!GET_ALLOC(HDRP(next_bp)))
		avail += next_size;

	if (avail >= asize) {
		/* Can expand in place */
		if (!GET_ALLOC(HDRP(next_bp)))
			remove_block(next_bp);
		prev_a = GET_PREV_ALLOC(HDRP(ptr));

		if (avail - asize >= MIN_BLK) {
			PUT(HDRP(ptr), PACK(asize, ALLOC_BIT | prev_a));
			rem = NEXT_BLKP(ptr);
			PUT(HDRP(rem), PACK(avail - asize, PREV_ALLOC_BIT));
			PUT(FTRP(rem), PACK(avail - asize, 0));
			insert_block(rem);
			after = NEXT_BLKP(rem);
			PUT(HDRP(after),
			    GET(HDRP(after)) & ~(uintptr_t)PREV_ALLOC_BIT);
		} else {
			PUT(HDRP(ptr), PACK(avail, ALLOC_BIT | prev_a));
			after = NEXT_BLKP(ptr);
			PUT(HDRP(after), GET(HDRP(after)) | PREV_ALLOC_BIT);
		}
		return (ptr);
	}

	/* Try to extend the heap if this block is at the end */
	end_bp = GET_ALLOC(HDRP(next_bp)) ? next_bp : NEXT_BLKP(next_bp);
	if (GET_SIZE(HDRP(end_bp)) == 0) {
		/* end_bp is the epilogue — extend heap */
		extend = asize - avail;
		if (mem_sbrk(extend) != (void *)-1) {
			if (!GET_ALLOC(HDRP(next_bp)))
				remove_block(next_bp);
			prev_a = GET_PREV_ALLOC(HDRP(ptr));
			PUT(HDRP(ptr),
			    PACK(avail + extend, ALLOC_BIT | prev_a));
			PUT(HDRP(NEXT_BLKP(ptr)),
			    PACK(0, ALLOC_BIT | PREV_ALLOC_BIT));
			return (ptr);
		}
	}

	/* Fallback: malloc + copy + free */
	newptr = mm_malloc(size);
	if (newptr == NULL)
		return (NULL);
	cpy = oldsize - WSIZE;
	if (size < cpy)
		cpy = size;
	memcpy(newptr, ptr, cpy);
	mm_free(ptr);
	return (newptr);
}

/*
 * coalesce - Coalesce a free block with adjacent free blocks.
 *   Uses prev_alloc bit to determine if previous block is free.
 *   Only free blocks have footers, so PREV_BLKP is only used
 *   when prev_alloc is 0.
 */
static void *
coalesce(void *bp)
{
	size_t prev_a = GET_PREV_ALLOC(HDRP(bp));
	size_t next_a = GET_ALLOC(HDRP(NEXT_BLKP(bp)));
	size_t size = GET_SIZE(HDRP(bp));

	if (prev_a && next_a) {
		/* Case 1: both neighbors allocated — nothing to merge */
	} else if (prev_a && !next_a) {
		/* Case 2: merge with next free block */
		void *next = NEXT_BLKP(bp);
		remove_block(next);
		size += GET_SIZE(HDRP(next));
		PUT(HDRP(bp), PACK(size, prev_a));
		PUT(FTRP(bp), PACK(size, 0));
	} else if (!prev_a && next_a) {
		/* Case 3: merge with previous free block */
		void *prev = PREV_BLKP(bp);
		size_t pp_a = GET_PREV_ALLOC(HDRP(prev));
		remove_block(prev);
		size += GET_SIZE(HDRP(prev));
		PUT(FTRP(bp), PACK(size, 0));
		PUT(HDRP(prev), PACK(size, pp_a));
		bp = prev;
	} else {
		/* Case 4: merge with both neighbors */
		void *prev = PREV_BLKP(bp);
		void *next = NEXT_BLKP(bp);
		size_t pp_a = GET_PREV_ALLOC(HDRP(prev));
		remove_block(prev);
		remove_block(next);
		size += GET_SIZE(HDRP(prev)) + GET_SIZE(HDRP(next));
		PUT(HDRP(prev), PACK(size, pp_a));
		PUT(FTRP(prev), PACK(size, 0));
		bp = prev;
	}

	/* Ensure next block knows we are free */
	PUT(HDRP(NEXT_BLKP(bp)),
	    GET(HDRP(NEXT_BLKP(bp))) & ~(uintptr_t)PREV_ALLOC_BIT);

	insert_block(bp);
	return (bp);
}

/*
 * extend_heap - Extend the heap by "size" bytes (rounded up to alignment).
 *   The old epilogue header becomes the new free block's header.
 */
static void *
extend_heap(size_t size)
{
	void *bp;
	size_t prev_a;

	/* Ensure 8-byte alignment */
	size = (size + (WSIZE - 1)) & ~(WSIZE - 1);
	if (size < MIN_BLK)
		size = MIN_BLK;

	if ((bp = mem_sbrk(size)) == (void *)-1)
		return (NULL);

	/* Inherit prev_alloc from old epilogue */
	prev_a = GET_PREV_ALLOC(HDRP(bp));
	PUT(HDRP(bp), PACK(size, prev_a));           /* Free block header */
	PUT(FTRP(bp), PACK(size, 0));                 /* Free block footer */
	PUT(HDRP(NEXT_BLKP(bp)), PACK(0, ALLOC_BIT)); /* New epilogue */

	return (coalesce(bp));
}

/*
 * find_fit - Find a free block of at least asize bytes.
 *   Best-fit within the matching size class, first-fit in larger classes.
 */
static void *
find_fit(size_t asize)
{
	int idx = class_index(asize);
	int i;
	void *bp;
	void *best;
	size_t bsize, best_size;

	/* Best fit within matching class */
	bp = FL_HEAD(idx);
	best = NULL;
	best_size = ~(size_t)0;

	while (bp != NULL) {
		bsize = GET_SIZE(HDRP(bp));
		if (bsize >= asize) {
			if (bsize == asize)
				return (bp);  /* Perfect fit — stop immediately */
			if (bsize < best_size) {
				best = bp;
				best_size = bsize;
			}
		}
		bp = NEXT_FREEP(bp);
	}
	if (best != NULL)
		return (best);

	/* First fit in larger classes */
	for (i = idx + 1; i < NUM_CLASSES; i++) {
		bp = FL_HEAD(i);
		if (bp != NULL)
			return (bp);
	}

	return (NULL);
}

/*
 * place - Allocate asize bytes in the free block bp.
 *   Splits if the remainder is large enough for a free block.
 */
static void
place(void *bp, size_t asize)
{
	size_t csize = GET_SIZE(HDRP(bp));
	size_t prev_a = GET_PREV_ALLOC(HDRP(bp));
	void *next;

	remove_block(bp);

	if ((csize - asize) >= MIN_BLK) {
		/* Split: allocate front, free remainder */
		PUT(HDRP(bp), PACK(asize, ALLOC_BIT | prev_a));
		next = NEXT_BLKP(bp);
		PUT(HDRP(next), PACK(csize - asize, PREV_ALLOC_BIT));
		PUT(FTRP(next), PACK(csize - asize, 0));
		insert_block(next);
	} else {
		/* No split: use entire block */
		PUT(HDRP(bp), PACK(csize, ALLOC_BIT | prev_a));
		next = NEXT_BLKP(bp);
		PUT(HDRP(next), GET(HDRP(next)) | PREV_ALLOC_BIT);
	}
}

/*
 * Heap consistency checker routines.
 */

static void
checkblock(void *bp)
{
	if ((uintptr_t)bp % WSIZE)
		printf("Error: %p is not word aligned\n", bp);
	if (!GET_ALLOC(HDRP(bp))) {
		if (GET_SIZE(HDRP(bp)) != GET_SIZE(FTRP(bp)))
			printf("Error: header/footer size mismatch at %p\n",
			    bp);
	}
}

void
checkheap(bool verbose)
{
	void *bp;

	if (verbose)
		printf("Heap (%p):\n", heap_listp);

	if (GET_SIZE(HDRP(heap_listp)) != DSIZE ||
	    !GET_ALLOC(HDRP(heap_listp)))
		printf("Bad prologue header\n");
	checkblock(heap_listp);

	for (bp = heap_listp; GET_SIZE(HDRP(bp)) > 0; bp = NEXT_BLKP(bp)) {
		if (verbose)
			printblock(bp);
		checkblock(bp);
	}

	if (verbose)
		printblock(bp);
	if (GET_SIZE(HDRP(bp)) != 0 || !GET_ALLOC(HDRP(bp)))
		printf("Bad epilogue header\n");
}

static void
printblock(void *bp)
{
	size_t hsize = GET_SIZE(HDRP(bp));
	bool halloc = GET_ALLOC(HDRP(bp));

	if (hsize == 0) {
		printf("%p: end of heap\n", bp);
		return;
	}

	printf("%p: header: [%zu:%c] prev_alloc:%c\n", bp,
	    hsize, (halloc ? 'a' : 'f'),
	    GET_PREV_ALLOC(HDRP(bp)) ? 'y' : 'n');
}

